import * as React from 'react';

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'default' | 'outline' | 'ghost' | 'destructive';
  size?: 'default' | 'sm' | 'lg' | 'icon';
}

export const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className = '', variant = 'default', size = 'default', ...props }, ref) => {
    const baseStyles = 'inline-flex items-center justify-center rounded-md font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 disabled:pointer-events-none disabled:opacity-50';

    const variantStyles = {
      default: 'bg-blue-600 text-white hover:bg-blue-700',
      outline: 'border border-input bg-background hover:bg-accent',
      ghost: 'hover:bg-accent hover:text-accent-foreground',
    };

    const sizeStyles = {
      default: 'h-10 px-4 py-2',
      sm: 'h-9 rounded-md px-3',
      lg: 'h-11 rounded-md px-8',
    };

    return (
      <button
        ref={ref}
        className={`${baseStyles} ${variantStyles[variant]} ${sizeStyles[size]} ${className}`}
        {...props}
      />
    );
  }
);
Button.displayName = 'Button';

import { Task } from '@/types';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { User, Lock } from 'lucide-react';

interface TaskCardProps {
  task: Task;
  onClaim?: (taskId: number) => void;
  onRelease?: (taskId: number) => void;
  currentUserId?: string;
}

export function TaskCard({ task, onClaim, onRelease, currentUserId }: TaskCardProps) {
  const isClaimable = !task.owner && onClaim;
  const isReleasable = task.owner === currentUserId && onRelease;
  const isOwned = task.owner === currentUserId;

  const getStatusBadge = () => {
    switch (task.status) {
      case 'pending':
        return <Badge variant="secondary">待认领</Badge>;
      case 'in_progress':
        return <Badge variant="default">进行中</Badge>;
      case 'completed':
        return <Badge variant="outline">已完成</Badge>;
    }
  };

  return (
    <Card className="hover:shadow-md transition-shadow">
      <CardHeader className="pb-2">
        <div className="flex items-start justify-between gap-2">
          <CardTitle className="text-sm font-medium line-clamp-2 flex-1">
            {task.subject}
          </CardTitle>
          {getStatusBadge()}
        </div>
      </CardHeader>
      <CardContent>
        {task.description && (
          <p className="text-xs text-muted-foreground mb-2 line-clamp-3">
            {task.description}
          </p>
        )}

        {task.requiredRole && (
          <div className="flex items-center gap-1 text-xs text-muted-foreground mb-2">
            <Lock className="h-3 w-3" />
            <span>需要: {task.requiredRole}</span>
          </div>
        )}

        {task.owner && (
          <div className="flex items-center gap-1 text-xs text-muted-foreground mb-2">
            <User className="h-3 w-3" />
            <span>负责人: {task.owner}</span>
          </div>
        )}

        {task.blockedBy.length > 0 && (
          <div className="text-xs text-muted-foreground">
            依赖: {task.blockedBy.join(', ')}
          </div>
        )}

        {(isClaimable || isReleasable) && (
          <div className="mt-3 pt-2 border-t">
            {isClaimable && (
              <Button 
                size="sm" 
                className="w-full"
                onClick={() => onClaim?.(task.id)}
              >
                认领任务
              </Button>
            )}
            {isReleasable && (
              <Button 
                size="sm" 
                variant="outline"
                className="w-full"
                onClick={() => onRelease?.(task.id)}
              >
                释放任务
              </Button>
            )}
          </div>
        )}
      </CardContent>
    </Card>
  );
}

import { Message } from '@/types';
import { User } from 'lucide-react';

interface MessageBubbleProps {
  message: Message;
}

export function MessageBubble({ message }: MessageBubbleProps) {
  const isUser = message.type === 'user';
  const isSystem = message.type === 'system';
  const isTool = message.type === 'tool';

  return (
    <div
      className={`flex gap-3 mb-4 ${
        isUser ? 'justify-end' : 'justify-start'
      }`}
    >
      {isUser && (
        <div className="flex flex-col items-end max-w-[80%]">
          <div className="bg-primary text-primary-foreground px-4 py-2 rounded-lg">
            <p className="whitespace-pre-wrap break-words">{message.content}</p>
          </div>
          <span className="text-xs text-muted-foreground mt-1">
            {new Date(message.timestamp).toLocaleTimeString()}
          </span>
        </div>
      )}

      {isSystem && (
        <div className="flex flex-col max-w-[80%]">
          <div className="bg-muted px-4 py-2 rounded-lg border">
            <p className="text-sm text-muted-foreground">{message.content}</p>
          </div>
          <span className="text-xs text-muted-foreground mt-1">
            {new Date(message.timestamp).toLocaleTimeString()}
          </span>
        </div>
      )}

      {!isUser && !isSystem && (
        <div className="flex gap-3 max-w-[80%]">
          <div className="flex-shrink-0">
            <div className="h-8 w-8 bg-secondary rounded-full flex items-center justify-center">
              <User className="h-4 w-4 text-secondary-foreground" />
            </div>
          </div>
          <div className="flex flex-col flex-1">
            <div className="bg-secondary/50 px-4 py-2 rounded-lg">
              <p className="whitespace-pre-wrap break-words">{message.content}</p>
              {message.toolCalls && message.toolCalls.length > 0 && (
                <div className="mt-2 border-t pt-2">
                  <p className="text-xs text-muted-foreground mb-1">
                    工具调用:
                  </p>
                  {message.toolCalls.map((tool) => (
                    <div key={tool.id} className="text-xs font-mono bg-muted px-2 py-1 rounded">
                      {tool.name}({JSON.stringify(tool.args)})
                    </div>
                  ))}
                </div>
              )}
            </div>
            <span className="text-xs text-muted-foreground mt-1">
              {new Date(message.timestamp).toLocaleTimeString()}
            </span>
          </div>
        </div>
      )}
    </div>
  );
}

