import React, { useState, useRef, useEffect } from 'react';
import { useChatStore } from '../../stores/chatStore';
import { Message } from '../../types';
import { Button } from '../ui/button';
import { Textarea } from '../ui/textarea';
import { ScrollArea } from '../ui/scroll-area';
import { Badge } from '../ui/badge';

export const ChatView: React.FC = () => {
  const { messages, isStreaming, connection, addMessage, updateLastMessage, setStreaming } = useChatStore();
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // 自动滚动到底部
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isStreaming]);

  useEffect(() => {
    // 设置 SSE 事件监听
    sseService.onMessage((event) => {
      switch (event.event) {
        case 'token':
          updateLastMessage(event.data as string);
          break;
        case 'done':
          setStreaming(false);
          break;
        case 'error':
          console.error('SSE error:', event.data);
          setStreaming(false);
          break;
      }
    });

    return () => {
      sseService.disconnect();
    };
  }, [updateLastMessage, setStreaming]);

  const handleSend = () => {
    if (!input.trim() || isStreaming) return;

    // 添加用户消息
    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: input,
      timestamp: Date.now(),
    };
    addMessage(userMessage);

    // 添加空的助手消息
    const assistantMessage: Message = {
      id: (Date.now() + 1).toString(),
      role: 'assistant',
      content: '',
      timestamp: Date.now(),
    };
    addMessage(assistantMessage);

    // 开始 SSE 流
    setStreaming(true);
    setInput('');

    // TODO: Implement SSE connection
    console.log('Would connect SSE for:', userMessage.content);
    setStreaming(false);
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="flex h-full flex-col">
      {/* Header */}
      <div className="flex h-14 items-center justify-between border-b px-6">
        <h2 className="text-lg font-semibold">对话</h2>
        <div className="flex items-center gap-2">
          <Badge variant={connection.status === 'connected' ? 'default' : 'destructive'}>
            {connection.status === 'connected' ? '已连接' : '未连接'}
          </Badge>
        </div>
      </div>

      {/* Messages */}
      <ScrollArea ref={scrollRef} className="flex-1 p-6 space-y-4">
        {messages.length === 0 && (
          <div className="flex h-full flex-col items-center justify-center text-muted-foreground">
            <Bot className="mb-4 h-16 w-16" />
            <p className="text-lg">开始对话</p>
            <p className="text-sm">输入问题，与 AI 助手开始交互</p>
          </div>
        )}

        {messages.map((message) => (
          <div
            key={message.id}
            className={`flex gap-3 ${
              message.type === 'user' ? 'flex-row-reverse' : 'flex-row'
            }`}
          >
            <div
