              <p className="whitespace-pre-wrap break-words">{message.content}</p>
            </div>
          </div>
        ))}
      </ScrollArea>

      {/* Input */}
      <div className="border-t p-6">
        <div className="flex gap-2">
          <Textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="输入消息... (Shift+Enter 换行)"
